class UFU_User_Files_Upload {
    private static $instance = null;
    private $upload_subdir = 'user-files';

    public static function instance() {
        if (null === self::$instance) {
            self::$instance = new self();
        }
        return self::$instance;
    }

    private function __construct() {
        add_shortcode('user_file_upload', array($this, 'render_shortcode'));
        add_action('init', array($this, 'handle_upload'));
        add_action('wp_enqueue_scripts', array($this, 'enqueue_assets'));
    }

    public function enqueue_assets() {
        wp_register_style('ufu-user-files-upload', false);
        wp_enqueue_style('ufu-user-files-upload');
        $css = '
            .ufu-upload-wrap{max-width:600px;padding:20px;border:1px solid #ddd;border-radius:8px}
            .ufu-upload-wrap label{display:block;margin:0 0 8px;font-weight:600}
            .ufu-upload-wrap input[type="file"]{display:block;margin:0 0 16px}
            .ufu-upload-wrap .ufu-message{margin:0 0 16px;padding:10px 12px;border-radius:4px}
            .ufu-upload-wrap .ufu-success{background:#e7f7ec;color:#1e6b2b}
            .ufu-upload-wrap .ufu-error{background:#fde8e8;color:#9b1c1c}
        ';
        wp_add_inline_style('ufu-user-files-upload', $css);
    }

    public function render_shortcode() {
        if (!is_user_logged_in()) {
            return '<div class="ufu-upload-wrap"><p>You must be logged in to upload files.</p></div>';
        }

        $message = '';
        if (isset($_GET['ufu_upload']) && $_GET['ufu_upload'] === 'success') {
            $message = '<div class="ufu-message ufu-success">File uploaded successfully.</div>';
        } elseif (isset($_GET['ufu_upload']) && $_GET['ufu_upload'] === 'error') {
            $message = '<div class="ufu-message ufu-error">File upload failed.</div>';
        }

        ob_start();
        ?>
        <div class="ufu-upload-wrap">
            <?php echo $message; ?>
            <form method="post" enctype="multipart/form-data">
                <?php wp_nonce_field('ufu_user_file_upload', 'ufu_nonce'); ?>
                <input type="hidden" name="ufu_upload_action" value="1">
                <label for="ufu_file">Upload Profile Picture or Document</label>
                <input type="file" name="ufu_file" id="ufu_file" accept=".jpg,.jpeg,.png,.gif,.pdf,.doc,.docx,.txt,.rtf,.odt,.xls,.xlsx,.ppt,.pptx,image/*,application/pdf,application/msword,application/vnd.openxmlformats-officedocument.wordprocessingml.document">
                <button type="submit">Upload File</button>
            </form>
        </div>
        <?php
        return ob_get_clean();
    }

    public function handle_upload() {
        if (!isset($_POST['ufu_upload_action'])) {
            return;
        }

        if (!is_user_logged_in()) {
            $this->redirect_with_status('error');
        }

        if (
            !isset($_POST['ufu_nonce']) ||
            !wp_verify_nonce(sanitize_text_field(wp_unslash($_POST['ufu_nonce'])), 'ufu_user_file_upload')
        ) {
            $this->redirect_with_status('error');
        }

        if (empty($_FILES['ufu_file']) || !isset($_FILES['ufu_file']['name']) || empty($_FILES['ufu_file']['name'])) {
            $this->redirect_with_status('error');
        }

        $file = $_FILES['ufu_file'];

        if (!empty($file['error'])) {
            $this->redirect_with_status('error');
        }

        $allowed_mimes = array(
            'jpg|jpeg|jpe' => 'image/jpeg',
            'png'           => 'image/png',
            'gif'           => 'image/gif',
            'pdf'           => 'application/pdf',
            'doc'           => 'application/msword',
            'docx'          => 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
            'txt'           => 'text/plain',
            'rtf'           => 'application/rtf',
            'odt'           => 'application/vnd.oasis.opendocument.text',
            'xls'           => 'application/vnd.ms-excel',
            'xlsx'          => 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
            'ppt'           => 'application/vnd.ms-powerpoint',
            'pptx'          => 'application/vnd.openxmlformats-officedocument.presentationml.presentation',
        );

        $filetype = wp_check_filetype_and_ext($file['tmp_name'], $file['name'], $allowed_mimes);
        if (empty($filetype['ext']) || empty($filetype['type'])) {
            $this->redirect_with_status('error');
        }

        $upload_dir = wp_upload_dir();
        if (!empty($upload_dir['error'])) {
            $this->redirect_with_status('error');
        }

        $target_dir = trailingslashit($upload_dir['basedir']) . $this->upload_subdir;
        if (!file_exists($target_dir)) {
            wp_mkdir_p($target_dir);
        }

        if (!is_dir($target_dir) || !is_writable($target_dir)) {
            $this->redirect_with_status('error');
        }

        $user = wp_get_current_user();
        $sanitized_name = sanitize_file_name($file['name']);
        $unique_name = wp_unique_filename($target_dir, $sanitized_name);
        $new_file = trailingslashit($target_dir) . $unique_name;

        if (!move_uploaded_file($file['tmp_name'], $new_file)) {
            $this->redirect_with_status('error');
        }

        $file_url = trailingslashit($upload_dir['baseurl']) . $this->upload_subdir . '/' . $unique_name;

        $attachment = array(
            'post_mime_type' => $filetype['type'],
            'post_title'     => sanitize_file_name(pathinfo($unique_name, PATHINFO_FILENAME)),
            'post_content'   => '',
            'post_status'    => 'inherit',
            'post_author'    => $user->ID,
        );

        $attachment_id = wp_insert_attachment($attachment, $new_file);
        if ($attachment_id) {
            require_once ABSPATH . 'wp-admin/includes/image.php';
            $attach_data = wp_generate_attachment_metadata($attachment_id, $new_file);
            wp_update_attachment_metadata($attachment_id, $attach_data);
            update_post_meta($attachment_id, '_ufu_uploaded_by', $user->ID);
            update_post_meta($attachment_id, '_ufu_original_name', sanitize_file_name($file['name']));
            update_post_meta($attachment_id, '_ufu_file_url', esc_url_raw($file_url));
        }

        $this->redirect_with_status('success');
    }

    private function redirect_with_status($status) {
        $redirect = wp_get_referer();
        if (!$redirect) {
            $redirect = home_url('/');
        }
        $redirect = add_query_arg('ufu_upload', $status, $redirect);
        wp_safe_redirect($redirect);
        exit;
    }
}

